// ════════════════════════════════════════════════════════════════════
//  ▼▼▼  CONFIG — EDIT EVERY VALUE IN THIS BLOCK, THEN SAVE  ▼▼▼
// ════════════════════════════════════════════════════════════════════
const CONFIG = {
  // ---- API KEYS ----
  FAL_KEY:         'YOUR_FAL_KEY_HERE',
  ANTHROPIC_KEY:   'YOUR_ANTHROPIC_KEY_HERE',

  // ---- SUPABASE ----
  // ---- SUPABASE ----
    SUPABASE_URL:   'https://hgmvgnsvxlzcylfwttlc.supabase.co',   // no trailing slash
  SUPABASE_SECRET: 'YOUR_SUPABASE_SECRET_HERE',


  // ---- PRODUCT REFERENCE IMAGE FILE IDS (plain IDs, not URLs) ----
 PRODUCT_FILE_IDS: [
    '10i08pjUJeFojyPXet4_AojZ9uSVcN1Cu',
    '1Hgtdkqxz1Se0pXyN2LKiZG5u8BL34NIZ'
  ],


      // ---- GOOGLE DRIVE FOLDER IDS (open the folder, copy the id in the URL)
  DRIVE_PERSONAS_FOLDER_ID: '1r5z9i2XTfBM-QzVqDUVFidaVJjv_FXoJ',
  DRIVE_OUTPUTS_FOLDER_ID:  '1Y-qCUx4MuK2FC_puRtSsNxtwPKi6wApI',


  // ---- MODELS ----
  ANTHROPIC_MODEL: 'claude-sonnet-4-6',     // writes the image prompts (fast + excellent)
  QC_MODEL:        'claude-sonnet-4-6',     // vision QC
  FAL_T2I_MODEL:   'fal-ai/nano-banana-pro',
  FAL_EDIT_MODEL:  'fal-ai/nano-banana-pro/edit',

  // ---- GENERATION SETTINGS ----
  PERSONA_ASPECT:  '3:4',
  SCENE_ASPECT:    '9:16',
  QC_PASS_SCORE:   60,     // lenient QC: pass unless a real defect drags score below this

  // ============================================================
  //  RUN CONTROL  -  every run does FULL video creation
  //  (scene image -> QC -> video). There is no image-only mode.
  // ============================================================

  // ONE_PER_PERSONA:
  //   true  -> EVERY persona is processed this run. Each persona gets its
  //            next N undone scenarios (N = MAX_VIDEOS_PER_RUN). Max
  //            diversity: 10 personas, N=1 -> 10 videos, each a different
  //            persona. No waiting for a persona to finish all 30.
  //   false -> ONLY personas with NO video yet (newly added accounts
  //            catching up). Each gets its next N scenarios.
  ONE_PER_PERSONA: true,

  // TIKTOK_ID:  targeting override. When set, ONE_PER_PERSONA is ignored.
  //   false              -> not used
  //   'tt_abc'           -> only that one account's persona
  //   'tt_abc, tt_def'   -> several accounts (comma-separated tiktok_id values)
  //   Each targeted persona gets its next N undone scenarios.
  TIKTOK_ID: 'sahad123',

  // Scenarios processed PER PERSONA this run (lowest undone scenario ids
  // first). Total videos = (personas selected) x this number.
  // Keep the total within the n8n 40-min execution limit (~8-10 videos).
  MAX_VIDEOS_PER_RUN:  1,

  // QC retry loop: times ONE scene image is regenerated within a run when it
  // fails QC. If still not clean after this many attempts, that SCENARIO is
  // skipped (no video for it) and the planner moves to the persona's next
  // scenario. Re-run later to retry skipped scenarios.
  MAX_QC_ATTEMPTS:  3,

  // ---- PHASE C: VIDEO (Seedance 2.0 on fal.ai) ----
  // The brand/product .json you place in your Drive 'information' folder.

  INFO_FILE_ID:        '1aOB0XqfaMiKzWPbKPuZnkxsvCLzq7lAi',
  FAL_VIDEO_MODEL:     'bytedance/seedance-2.0/reference-to-video',
  VIDEO_DURATION:      '15',         // seconds, string. Seedance native range "4"-"15".
  VIDEO_RESOLUTION:    '1080p',      // '720p' or '1080p'
  VIDEO_ASPECT:        '9:16',
  VIDEO_GENERATE_AUDIO: true,        // native audio + lip-sync

  // ============================================================
  //  PHASE D  -  TikTok auto-post
  // ============================================================
  TIKTOK_AUTO_POST:    false,                 // true -> Phase D runs after Phase C
  TIKTOK_CLIENT_KEY:   'PASTE_tiktok_client_key',
  TIKTOK_CLIENT_SECRET:'PASTE_tiktok_client_secret',
  TIKTOK_POST_PRIVACY: 'SELF_ONLY',           // 'SELF_ONLY' until app is audited, then 'PUBLIC_TO_EVERYONE'
};
// ════════════════════════════════════════════════════════════════════
return [{ json: CONFIG }];

const items = $('Worker Trigger').all();
const it = (items && items[0] && items[0].json) || $input.first().json || {};
return [{ json: it }];

// Loads every persona from Supabase, with its tiktok_account joined.
const cfg = $('Config').first().json;
const H = { apikey: cfg.SUPABASE_SECRET };
const personas = await this.helpers.httpRequest({
  method: 'GET', url: cfg.SUPABASE_URL + '/rest/v1/personas?select=*,tiktok_accounts(*)', headers: H, json: true });
if (!personas || personas.length === 0) throw new Error('No personas found in Supabase yet.');
return personas.map(p => ({ json: p }));

// One item per Drive file to download: unique persona images + product images.
const cfg = $('Config').first().json;
const files = []; const seen = new Set();
for (const item of $input.all()) {
  const fid = item.json.drive_file_id;
  if (fid && !seen.has(fid)) { seen.add(fid); files.push({ json: { fileId: fid, kind: 'persona' } }); }
}
for (const pid of (cfg.PRODUCT_FILE_IDS || [])) {
  if (pid && !seen.has(pid)) { seen.add(pid); files.push({ json: { fileId: pid, kind: 'product' } }); }
}
if (files.length === 0) throw new Error('No reference files to download.');
return files;

// Converts every downloaded reference image into a base64 data URI.
const cfg = $('Config').first().json;
const productSet = new Set(cfg.PRODUCT_FILE_IDS || []);
const items = $input.all();
const library = {}; const products = [];
for (let i = 0; i < items.length; i++) {
  const j = items[i].json || {};
  const id = j.id || j.fileId;
  if (!items[i].binary || !items[i].binary.data) continue;
  const buf = await this.helpers.getBinaryDataBuffer(i, 'data');
  const mime = (items[i].binary.data.mimeType) || 'image/png';
  const uri = 'data:' + mime + ';base64,' + buf.toString('base64');
  if (id) library[id] = uri;
  if (productSet.has(id)) products.push(uri);
}
return [{ json: { library, products } }];

// Worker-mode job emitter. Reads the single job directly from Worker Trigger.
const wt = $('Worker Trigger').all();
const j = (wt && wt[0] && wt[0].json) || $('Normalise Job').first().json || {};
if (j.persona_id == null) {
  throw new Error('Worker received no job data. Orchestrator must pass {persona_id, scenario_id, scenario, ...}. Got: ' + JSON.stringify(j));
}
return [{ json: {
  persona_id: j.persona_id,
  persona_drive_file_id: j.persona_drive_file_id,
  gender: j.gender || 'female',
  country: j.country || '',
  age: j.age != null ? j.age : null,
  scenario: j.scenario || { id: j.scenario_id }
} }];

// Per job: resolves the gender-correct outfit and builds the Anthropic
// request that writes the Nano Banana edit prompt.
const cfg = $('Config').first().json;
const SCENE_WRITER_SYSTEM = `You are an elite photographic art director and prompt engineer. You write ONE production prompt for Google's Nano Banana Pro (Gemini 3 Pro Image) image-EDIT model, which composes a new photograph out of reference images.

WHAT YOU ARE GIVEN
- A SCENE BRIEF in JSON (scene, outfit, pose, hand grip, lighting, mood, palette, framing, camera).
- The editor receives REFERENCE IMAGES in this fixed order: image 1 = THE PERSON (a real individual - the locked identity). image 2 onward = THE PRODUCT, a small rectangular box with a labelled front face, shown from several angles.

YOUR OUTPUT
- Output ONLY the final prompt text. No preamble, no quotes, no markdown, no labels, no commentary.
- Write rich, flowing, photographic prose - one to three dense paragraphs. Nano Banana Pro has a very large context window and rewards precise, concrete specificity, so never be terse.

NON-NEGOTIABLE RULES

1. REFERENCE RELATIONSHIP. Open by stating exactly how to use the references: take the exact person from image 1 and the exact product from the remaining images, and place them together in one new photograph.

2. IDENTITY LOCK. Command the model to preserve, with zero alteration, the person's face, facial structure and bone structure, eye colour and shape, nose, jawline, complexion and exact skin tone, and their natural hair colour, length and texture, exactly as in image 1. Only hair styling, clothing, expression and pose change. The face must be unmistakably the same individual.

3. PRODUCT LOCK. Command the model to reproduce the product exactly as in the product images - identical shape, proportions, colours, label artwork, logo and text. It is a real physical object placed in the scene; never redesigned, relabelled, warped or invented.

4. TRANSLATE THE BRIEF FAITHFULLY. Convert every field of the scene brief into vivid visual description: the environment, the outfit (use exactly the gender-correct outfit text supplied), the hair styling, the precise body pose, the exact hand-and-grip mechanics, the lighting setup, the colour palette, the camera framing and the camera height.

5. HANDS AND GRIP. Describe the hands with anatomical precision: a natural human hand with exactly five correctly proportioned fingers, and a believable, physically plausible grip on the product exactly as the brief specifies. The product sits in or on the hand with correct contact and occlusion - solidly held.

6. PHOTOREALISM. State it is a real photograph: full-frame camera, a fast prime lens around 35-50mm, aperture near f/2.0 giving a natural shallow depth of field, authentic colour and true-to-life contrast. Demand REAL human skin with visible pores, fine texture, faint natural lines and a natural sheen. The result should read as a genuine, high-quality user-generated lifestyle photo for social media - authentic and candid in feel, yet crisp and well exposed.

7. FRAMING. The final image is a vertical 9:16 frame. State the framing and crop from the brief and keep both the person and the product clearly visible and well composed, with the product's labelled front face oriented toward the camera as the grip and placement description requires.

8. POSITIVE FRAMING ONLY. Describe only what IS present. Never use negations - Nano Banana does not reliably honour them. Any correction must be phrased as the desired positive state.

Write the single best prompt you can. Every word must earn its place.`;
return $input.all().map((it, i) => {
  const job = it.json;
  const sc = job.scenario;
  const outfit = (sc.outfit && (sc.outfit[job.gender] || sc.outfit.female || sc.outfit.male)) || '';
  const styleBrief = (sc.outfit && sc.outfit.style_brief) || '';
  const brief = JSON.stringify({
    scene: sc.scene, outfit_style_brief: styleBrief, outfit: outfit,
    pose: sc.pose, hand_assignment: sc.hand_assignment, grip_or_placement: sc.grip_or_placement,
    lighting: sc.lighting, mood: sc.mood, palette: sc.palette,
    framing: sc.framing, camera_height: sc.camera_height, aspect_ratio: cfg.SCENE_ASPECT
  }, null, 2);
  const userMsg = 'SCENE BRIEF (JSON):
' + brief
    + '

Reference images given to the editor, in order: image 1 = the PERSON (identity reference), '
    + 'image 2 onward = the PRODUCT shown from multiple angles.

Write the Nano Banana edit prompt now.';
  return { json: {
    job: job, scene_brief: brief,
    _url: 'https://api.anthropic.com/v1/messages',
    _headers: { 'x-api-key': cfg.ANTHROPIC_KEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
    _body: { model: cfg.ANTHROPIC_MODEL, max_tokens: 1800, system: SCENE_WRITER_SYSTEM, messages: [{ role: 'user', content: userMsg }] }
  }, pairedItem: { item: i } };
});

// Parses the Anthropic scene prompt and creates the uniform retry-loop item.
// Runs ONCE (before the loop), so index-correlation with Build Scene Prompt Req is safe.
const prev = $('B: Build Scene Prompt Req').all();
const items = $input.all();
const out = [];
for (let i = 0; i < items.length; i++) {
  const anth = items[i].json;
  const carried = prev[i].json;
  const prompt = (anth.content || []).filter(b => b.type === 'text').map(b => b.text).join('').trim();
  if (!prompt) continue;      // scene-prompt API errored for this job - skip it, retried next run
  out.push({ json: {
    job: carried.job,
    base_prompt: prompt,      // the original prompt, never mutated - retries rebuild from this
    prompt: prompt,           // the prompt actually sent this attempt
    corrective_history: [],   // positive correctives accumulated across attempts
    attempt: 1
  }, pairedItem: { item: i } });
}
return out;

// Builds the FAL nano-banana-pro/edit request from the carried loop item.
// Receives items from B: Prep Generation (attempt 1) OR from the QC retry
// loop (B: QC Passed? false branch) - both carry the same item shape.
const cfg = $('Config').first().json;
const lib = $('B: Build Image Library').first().json;
return $input.all().map((it, i) => {
  const d = it.json;
  const job = d.job;
  const personaUri = lib.library ? lib.library[job.persona_drive_file_id] : null;
  const refUris = [personaUri].concat(lib.products || []).filter(Boolean);
  return { json: {
    job: job, prompt: d.prompt, base_prompt: d.base_prompt,
    corrective_history: d.corrective_history || [], attempt: d.attempt || 1,
    _url: 'https://fal.run/' + cfg.FAL_EDIT_MODEL,
    _headers: { 'Authorization': 'Key ' + cfg.FAL_KEY, 'content-type': 'application/json' },
    _body: { prompt: d.prompt, image_urls: refUris, num_images: 1, output_format: 'png', aspect_ratio: cfg.SCENE_ASPECT }
  }, pairedItem: { item: i } };
});

// Builds the QC request. The generated image is passed to Claude BY URL
// (Anthropic supports url image sources) - it is never downloaded or held as
// base64 here, so retry attempts do not pile up image data in memory.
// Only the product reference images (from Drive) are sent as base64.
const cfg = $('Config').first().json;
const QC_SYSTEM = `You are a practical quality-control reviewer for AI-generated UGC advertising images. You are shown a GENERATED IMAGE under review, followed by one or more REFERENCE PRODUCT images showing what the real product box actually looks like.

Judge the GENERATED IMAGE on ONLY the three points below. Be lenient on everything else.

1. HUMAN ANATOMY. The person must be anatomically plausible: each visible hand has five well-formed fingers with no extra, missing or fused fingers; no extra or missing arms or legs; no warped or duplicated body parts; and a natural human face with realistic eyes, ears, mouth and teeth. Fail only for clear anatomical breakage.

2. PRODUCT RESEMBLANCE - this point is STRICT. Compare the product shown in the GENERATED image against the REFERENCE PRODUCT image(s). The product in the generated image must clearly be the SAME product, at an estimated 85 percent visual resemblance or higher. That means the same overall box shape and proportions, the same label layout, the same colours, and the same text and branding as the reference. PASS the product only when it is convincingly the same product at roughly 85 percent likeness or better. FAIL it when the product is missing, looks like a different or generic box, has a label, colours, text or shape that clearly differ from the reference, or is melted, garbled or duplicated. Do NOT judge the product orientation, angle, tilt, which side faces the camera, or where it sits in the frame - horizontal, vertical, tilted, near or far are all fine. What matters is that the product itself resembles the real one.

3. BASIC REALISM. The person should read as a real human. Skin only needs to be roughly natural - about 70 percent realistic or better is acceptable; allow minor imperfection and ordinary AI softness. Fail only for severely plastic, waxy or melted skin or faces, or gross artefacts such as floating objects, merged bodies or badly garbled text.

DO NOT CHECK AND DO NOT FAIL FOR: the scene, background, outfit, pose, framing, crop, camera angle, lighting or colour mood; the product orientation or placement; or any difference from an imagined brief. Judge ONLY the three points above.

SCORING: give an integer score from 0 to 100. Start at 100 and subtract only for the three defect types above. An image with sound anatomy, a product at 85 percent-or-better resemblance to the reference, and a roughly real-looking person should score high and pass.

CORRECTIVE - CRITICAL RULE. When (and only when) the image FAILS, also write a 'corrective': one short, concrete instruction describing the CORRECT state you want, phrased PURELY in the positive. The model that re-generates the image is Nano Banana, which has no mechanism for negative instructions - telling it what NOT to do achieves nothing or backfires. Never write a negation; always state the positive thing to do instead. Examples - Wrong: do not add a sixth finger. Right: render each hand with exactly five natural, correctly proportioned fingers. Wrong: the product should not look generic. Right: render the product box so it closely matches the reference product image - the same label layout, the same colours, the same text and the same proportions. If the image passes, set corrective to an empty string.

OUTPUT - return ONLY a single minified JSON object, no markdown and no commentary, in exactly this shape:
{"pass": <true or false>, "score": <0-100 integer>, "product_resemblance": <0-100 integer estimate>, "worst_defect": "<the single clearest real defect, or empty string>", "corrective": "<one positive do-this instruction, or empty string>"}

Set pass to true only when anatomy is sound, product_resemblance is about 85 or higher, and realism is acceptable.`;
const lib = $('B: Build Image Library').first().json;
const prev = $('B: Build FAL Edit Req').all();
const productBlocks = [];
for (const uri of (lib.products || [])) {
  const mm = /^data:([^;]+);base64,(.*)$/.exec(uri || '');
  if (mm) productBlocks.push({ type: 'image', source: { type: 'base64', media_type: mm[1], data: mm[2] } });
}
const items = $input.all();
const out = [];
for (let i = 0; i < items.length; i++) {
  const fal = items[i].json;
  const carried = prev[i].json;
  const url = fal && fal.images && fal.images[0] && fal.images[0].url;
  if (!url) continue;   // FAL produced nothing - dropped, retried on a later run
  const userContent = [
    { type: 'text', text: 'GENERATED IMAGE under review:' },
    { type: 'image', source: { type: 'url', url: url } },
    { type: 'text', text: 'REFERENCE PRODUCT image(s) - what the real product box looks like:' }
  ].concat(productBlocks).concat([
    { type: 'text', text: 'Return ONLY the JSON verdict.' }
  ]);
  out.push({ json: {
    job: carried.job, base_prompt: carried.base_prompt, prompt: carried.prompt,
    corrective_history: carried.corrective_history || [], attempt: carried.attempt || 1,
    sceneImageUrl: url,
    _url: 'https://api.anthropic.com/v1/messages',
    _headers: { 'x-api-key': cfg.ANTHROPIC_KEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
    _body: { model: cfg.QC_MODEL, max_tokens: 700, system: QC_SYSTEM, messages: [{ role: 'user', content: userContent }] }
  } });
}
return out;

// Parses the QC verdict and decides: finish, or retry with a corrected prompt.
// Correlates with B: Build QC Req (same loop iteration -> same item count).
const cfg = $('Config').first().json;
const maxAttempts = cfg.MAX_QC_ATTEMPTS || 3;
const passScore = (typeof cfg.QC_PASS_SCORE === 'number') ? cfg.QC_PASS_SCORE : 60;
const prev = $('B: Build QC Req').all();
return $input.all().map((it, i) => {
  const qcResp = it.json;
  const carried = prev[i].json;
  let qcText = (qcResp.content || []).filter(b => b.type === 'text').map(b => b.text).join('').trim();
  let qc;
  try { qc = JSON.parse(qcText.replace(/```json/gi, '').replace(/```/g, '').trim()); }
  catch (e) { qc = { pass: false, score: 0, product_resemblance: 0, worst_defect: 'QC verdict unavailable - will retry', corrective: '' }; }
  const passed = (qc.pass === true) || (typeof qc.score === 'number' && qc.score >= passScore);
  const attempt = carried.attempt || 1;
  const exhausted = attempt >= maxAttempts;
  const done = passed || exhausted;            // leave the loop if passed OR out of attempts
  // Accumulate the positive correctives. Rebuild the prompt from the ORIGINAL
  // base_prompt + every corrective so far (all are 'do this' instructions, so
  // they stack cleanly - this is the Nano Banana positive-framing approach).
  const history = (carried.corrective_history || []).slice();
  if (!passed && qc.corrective && history.indexOf(qc.corrective) === -1) history.push(qc.corrective);
  let nextPrompt = carried.base_prompt;
  if (history.length) {
    nextPrompt = carried.base_prompt
      + '\n\nADDITIONAL REQUIREMENTS - render the image so that all of the following are clearly true: '
      + history.join('  ');
  }
  return { json: {
    job: carried.job,
    base_prompt: carried.base_prompt,
    prompt: done ? carried.prompt : nextPrompt,   // retry uses the corrected prompt
    corrective_history: history,
    attempt: done ? attempt : attempt + 1,
    sceneImageUrl: carried.sceneImageUrl,
    qc_passed: passed,
    qc_score: (qc.score != null ? qc.score : ''),
    qc_resemblance: (qc.product_resemblance != null ? qc.product_resemblance : ''),
    qc_worst: qc.worst_defect || '',
    _done: done
  }, pairedItem: { item: i } };
});

// Prepares the final image binary and DB record fields.
// The image is downloaded from its FAL URL once, for the image
// that finished the QC loop. No base64 was carried through the loop.
const items = $input.all();
const out = [];
for (let i = 0; i < items.length; i++) {
  const d = items[i].json;
  const job = d.job;
  const sc = job.scenario;
  if (!d.sceneImageUrl) continue;
  const filename = 'scene_p' + job.persona_id + '__' + sc.id + '.png';
  const raw = await this.helpers.httpRequest({ method: 'GET', url: d.sceneImageUrl, encoding: 'arraybuffer', timeout: 120000 });
  const binaryData = await this.helpers.prepareBinaryData(Buffer.from(raw), filename, 'image/png');
  out.push({
    json: {
      persona_id: job.persona_id, scenario_id: sc.id, scenario_title: sc.id,
      qc_status: d.qc_passed ? 'pass' : 'skipped',
      qc_reason: String((d.qc_worst || (d.qc_passed ? 'ok' : 'unresolved'))
                 + ' | score ' + (d.qc_score !== '' && d.qc_score != null ? d.qc_score : 'n/a')
                 + ' | resemblance ' + (d.qc_resemblance !== '' && d.qc_resemblance != null ? d.qc_resemblance : 'n/a')
                 + ' | attempts ' + d.attempt).slice(0, 400),
      attempts: d.attempt, prompt_used: d.prompt, scene_filename: filename
    },
    binary: { data: binaryData }
  });
}
return out;

// Inserts each generated scene into Supabase outputs (upsert on persona_id+scenario_id).
const cfg = $('Config').first().json;
const H = { apikey: cfg.SUPABASE_SECRET, 'content-type': 'application/json',
            Prefer: 'return=representation,resolution=merge-duplicates' };
const gens = $('B: Finalize Scene').all().map(i => i.json);
const byName = {};
for (const g of gens) byName[g.scene_filename] = g;
const out = [];
for (const item of $input.all()) {
  const f = item.json;
  const g = byName[f.name] || {};
  const row = {
    persona_id: g.persona_id, scenario_id: g.scenario_id, scenario_title: g.scenario_title,
    drive_file_id: f.id,
    drive_url: f.webViewLink || ('https://drive.google.com/file/d/' + f.id + '/view'),
    qc_status: g.qc_status, qc_reason: g.qc_reason, attempts: g.attempts
  };

  const res = await this.helpers.httpRequest({
    method: 'POST', url: cfg.SUPABASE_URL + '/rest/v1/outputs?on_conflict=persona_id,scenario_id',
    headers: H, body: row, json: true });
  out.push({ json: { recorded: Array.isArray(res) ? res[0] : res } });
}
return out;

// WORKER-MODE C planner. Builds exactly ONE video job for the persona+scenario
// this Worker received from the Orchestrator. No global DB scan, no flags
// reading. Phase B (in this same Worker run) just wrote the output row, so we
// fetch THAT row and use its drive_file_id for the video.
const cfg = $('Config').first().json;
const H = { apikey: cfg.SUPABASE_SECRET };

// The job this Worker is processing — set by Worker Trigger.
const wt = $('Worker Trigger').all();
const job = (wt && wt[0] && wt[0].json) || {};
if (!job.persona_id || !job.scenario) {
  throw new Error('C planner: missing job context. Got: ' + JSON.stringify(job));
}

// ---- Look up the output Phase B just wrote (persona_id + scenario_id) ----
const outputs = await this.helpers.httpRequest({ method: 'GET',
  url: cfg.SUPABASE_URL + '/rest/v1/outputs?select=*'
       + '&persona_id=eq.' + job.persona_id
       + '&scenario_id=eq.' + encodeURIComponent(job.scenario.id)
       + '&qc_status=eq.pass',
  headers: H, json: true });
if (!outputs || outputs.length === 0) {
  // Phase B didn't produce a passed image for this job → nothing to video.
  // Exit cleanly; the run continues, the next persona+scenario will be a
  // fresh Worker execution.
  return [];
}
const o = outputs[0];

// ---- Skip if this output already has a video (resumability) ----
let existing = [];
try {
  existing = await this.helpers.httpRequest({ method: 'GET',
    url: cfg.SUPABASE_URL + '/rest/v1/videos?select=output_id&output_id=eq.' + o.id,
    headers: H, json: true });
} catch (e) { existing = []; }
if (existing && existing.length > 0) return [];

// ---- Look up the persona's account for the presenter profile ----
let personas = [], accounts = [];
try {
  personas = await this.helpers.httpRequest({ method: 'GET',
    url: cfg.SUPABASE_URL + '/rest/v1/personas?select=id,tiktok_account_id&id=eq.' + job.persona_id,
    headers: H, json: true });
} catch (e) { personas = []; }
const persona = (personas && personas[0]) || {};
if (persona.tiktok_account_id) {
  try {
    accounts = await this.helpers.httpRequest({ method: 'GET',
      url: cfg.SUPABASE_URL + '/rest/v1/tiktok_accounts?select=id,name,gender,age,country,language'
           + '&id=eq.' + persona.tiktok_account_id,
      headers: H, json: true });
  } catch (e) { accounts = []; }
}
const account = (accounts && accounts[0]) || {};

// ---- Resolve language (same map / fallback as before) ----
const SUPPORTED = {english:'English',mandarin:'Mandarin Chinese',japanese:'Japanese',
  korean:'Korean',spanish:'Spanish',french:'French',german:'German',portuguese:'Portuguese'};
const COUNTRY_LANG = {
  'united states':'english','usa':'english','us':'english','united kingdom':'english',
  'uk':'english','england':'english','canada':'english','australia':'english',
  'new zealand':'english','ireland':'english','singapore':'english',
  'china':'mandarin','taiwan':'mandarin','hong kong':'mandarin',
  'japan':'japanese','south korea':'korean','korea':'korean',
  'spain':'spanish','mexico':'spanish','argentina':'spanish','colombia':'spanish',
  'chile':'spanish','peru':'spanish','venezuela':'spanish','ecuador':'spanish',
  'france':'french','belgium':'french','germany':'german','austria':'german','switzerland':'german',
  'portugal':'portuguese','brazil':'portuguese',
  'india':'hindi','saudi arabia':'arabic','united arab emirates':'arabic','uae':'arabic',
  'italy':'italian','russia':'russian','netherlands':'dutch','thailand':'thai',
  'indonesia':'indonesian','turkey':'turkish','poland':'polish'
};
function resolveLanguage(countryRaw) {
  const c = String(countryRaw || '').trim().toLowerCase();
  const official = COUNTRY_LANG[c] || 'english';
  if (SUPPORTED[official]) {
    return { spoken_language: SUPPORTED[official], language_is_native: true,
             accent_country: countryRaw || 'United States', fallback_used: false };
  }
  return { spoken_language: 'English', language_is_native: false,
           accent_country: countryRaw || 'United States', fallback_used: true,
           unsupported_official_language: official };
}
const lang = resolveLanguage(account.country);

// ---- Emit exactly the one video job ----
return [{ json: {
  output_id: o.id,
  scenario_id: o.scenario_id,
  scene_drive_file_id: o.drive_file_id,
  scenario: job.scenario,
  info_file_id: cfg.INFO_FILE_ID,
  persona_id: job.persona_id,
  presenter: {
    name:    account.name   || null,
    gender:  account.gender || 'female',
    age:     (account.age != null ? account.age : null),
    country: account.country || 'United States',
    account_language: account.language || null,
    spoken_language: lang.spoken_language,
    language_is_native: lang.language_is_native,
    accent_country: lang.accent_country,
    fallback_used: lang.fallback_used,
    unsupported_official_language: lang.unsupported_official_language || null
  }
} }];

// One Drive file per item to download: each scene image + the information config file.
const items = $input.all();
const files = []; const seen = new Set();
for (const it of items) {
  const fid = it.json.scene_drive_file_id;
  if (fid && !seen.has(fid)) { seen.add(fid); files.push({ json: { fileId: fid, kind: 'scene' } }); }
}
const infoId = items.length ? items[0].json.info_file_id : null;
if (infoId && !seen.has(infoId)) { seen.add(infoId); files.push({ json: { fileId: infoId, kind: 'info' } }); }
return files;

// Builds the video asset library: scene images -> base64 data URIs; info file -> parsed JSON.
const cfg = $('Config').first().json;
const items = $input.all();
const library = {}; let info = null;
for (let i = 0; i < items.length; i++) {
  const j = items[i].json || {};
  const id = j.id || j.fileId;
  if (!items[i].binary || !items[i].binary.data) continue;
  const buf = await this.helpers.getBinaryDataBuffer(i, 'data');
  if (id === cfg.INFO_FILE_ID) {
    try { info = JSON.parse(buf.toString('utf8')); }
    catch (e) { throw new Error('Could not parse the information file as JSON: ' + e.message); }
  } else {
    const mime = (items[i].binary.data.mimeType) || 'image/png';
    library[id] = 'data:' + mime + ';base64,' + buf.toString('base64');
  }
}
if (!info) throw new Error('Information config file not found - check INFO_FILE_ID in Config.');
return [{ json: { library, info } }];

// Parses the script JSON and builds the fal QUEUE submit request for Seedance 2.0.
// A for-loop (not .map) so a bad/truncated script can be skipped without
// killing the run - the rest of the videos still go through.
const cfg = $('Config').first().json;
const lib = $('C: Build Video Library').first().json;
const prev = $('C: Build Video Script Req').all();
const items = $input.all();
const out = [];
for (let i = 0; i < items.length; i++) {
  const cur = items[i].json || {};
  // retry path: item already carries a built job + prompt from a prior attempt
  if (cur && cur._retry === true && cur.job) {
    const sceneUriR = lib.library ? lib.library[cur.job.scene_drive_file_id] : null;
    if (sceneUriR) {
      out.push({ json: {
        job: cur.job, video_prompt: cur.video_prompt || '', dialogue: cur.dialogue || '',
        video_attempt: cur.video_attempt || 2,
        _url: 'https://queue.fal.run/' + cfg.FAL_VIDEO_MODEL,
        _headers: { 'Authorization': 'Key ' + cfg.FAL_KEY, 'content-type': 'application/json' },
        _body: {
          prompt: cur.video_prompt || '', image_urls: [sceneUriR],
          duration: String(cfg.VIDEO_DURATION), resolution: cfg.VIDEO_RESOLUTION,
          aspect_ratio: cfg.VIDEO_ASPECT, generate_audio: cfg.VIDEO_GENERATE_AUDIO !== false
        }
      } });
    }
    continue;
  }
  const anth = items[i].json;
  const pj = prev[i] && prev[i].json;
  if (!pj || !pj.job) continue;   // not a script item / index drift - skip safely
  const job = pj.job;
  // Anthropic ran out of tokens -> JSON is cut off mid-string. Skip this job
  // (raise max_tokens in C: Build Video Script Req if this happens a lot).
  if (anth && anth.stop_reason === 'max_tokens') continue;
  let txt = (anth.content || []).filter(b => b.type === 'text').map(b => b.text).join('').trim();
  let script;
  try { script = JSON.parse(txt.replace(/```json/gi, '').replace(/```/g, '').trim()); }
  catch (e) { continue; }   // malformed/truncated script - skip this one job
  if (!script || !script.prompt) continue;
  const sceneUri = lib.library ? lib.library[job.scene_drive_file_id] : null;
  if (!sceneUri) continue;  // scene image missing - skip, retried on a later run
  out.push({ json: {
    job: job, video_prompt: script.prompt || '', dialogue: script.dialogue || '', video_attempt: 1,
    _url: 'https://queue.fal.run/' + cfg.FAL_VIDEO_MODEL,
    _headers: { 'Authorization': 'Key ' + cfg.FAL_KEY, 'content-type': 'application/json' },
    _body: {
      prompt: script.prompt || '',
      image_urls: [sceneUri],
      duration: String(cfg.VIDEO_DURATION),
      resolution: cfg.VIDEO_RESOLUTION,
      aspect_ratio: cfg.VIDEO_ASPECT,
      generate_audio: cfg.VIDEO_GENERATE_AUDIO !== false
    }
  } });
}
return out;

// Reads the fal queue submit responses and prepares the polling loop.
// A single failed submit is skipped (that video is retried next run); the
// run only stops if EVERY submit failed - which points at a fal billing issue.
const prev = $('C: Build Video Submit Req').all();
const falKey = $('Config').first().json.FAL_KEY;
const items = $input.all();
const out = [];
for (let i = 0; i < items.length; i++) {
  const r = items[i].json || {};
  const carried = prev[i].json;
  const statusUrl = r.status_url || (r.response_url ? r.response_url + '/status' : null);
  const responseUrl = r.response_url;
  if (!statusUrl || !responseUrl) continue;   // this video failed to submit - skip it
  out.push({ json: {
    job: carried.job, video_prompt: carried.video_prompt, dialogue: carried.dialogue,
    video_attempt: carried.video_attempt || 1,
    _pollUrl: statusUrl, _resultUrl: responseUrl,
    _headers: { 'Authorization': 'Key ' + falKey }
  }, pairedItem: { item: i } });
}
if (out.length === 0 && items.length > 0) {
  throw new Error('No video jobs were accepted by fal - every submit failed. Check your fal.ai balance at fal.ai/dashboard/billing.');
}
return out;

// Inspects the fal queue status and decides: done, keep waiting, or retry.
// A fal-side failure (ERROR/FAILED status, or a 5xx error item from the poll
// HTTP node) no longer throws - it is flagged for an automatic resubmit,
// up to MAX_VIDEO_ATTEMPTS total tries.
const cfg = $('Config').first().json;
const MAX_VIDEO_ATTEMPTS = 2;   // total fal submit attempts per video
const ctx = $('C: Start Poll').all();
const items = $input.all();
let priorChecks = 0;
try { priorChecks = $('C: Check Video Status').all().length; } catch (e) { priorChecks = 0; }
if (priorChecks > 40) throw new Error('Video generation timed out after too many status polls.');
return items.map((it, i) => {
  const st = it.json || {};
  const carried = (ctx[i] ? ctx[i].json : ctx[0].json);
  const attempt = carried.video_attempt || 1;
  // fal poll itself errored (5xx / downstream_service_error) OR fal reports failure
  const httpErr = st && st.error;
  const status = String(st.status || '').toUpperCase();
  const falFailed = httpErr || status === 'ERROR' || status === 'FAILED';
  if (falFailed) {
    if (attempt < MAX_VIDEO_ATTEMPTS) {
      // flag for resubmit; carry the incremented attempt counter
      return { json: Object.assign({}, carried, { done: false, _retry: true,
        video_attempt: attempt + 1 }), pairedItem: { item: i } };
    }
    // attempts exhausted - give up on this video, no row written, retried next run
    return { json: Object.assign({}, carried, { done: false, _retry: false,
      _give_up: true }), pairedItem: { item: i } };
  }
  const done = (status === 'COMPLETED' || status === 'OK');
  return { json: Object.assign({}, carried, { done: done, _retry: false }),
           pairedItem: { item: i } };
});

// Inserts each generated video into Supabase `videos` (upsert on output_id).
const cfg = $('Config').first().json;
const H = { apikey: cfg.SUPABASE_SECRET, 'content-type': 'application/json',
            Prefer: 'return=representation,resolution=merge-duplicates' };
const gens = $('C: Prep Video Download').all().map(i => i.json);
const byName = {};
for (const g of gens) byName[g.video_filename] = g;
const out = [];
for (const item of $input.all()) {
  const f = item.json;
  const g = byName[f.name] || {};
  const row = {
    output_id: g.output_id, scenario_id: g.scenario_id,
    drive_file_id: f.id,
    drive_url: f.webViewLink || ('https://drive.google.com/file/d/' + f.id + '/view'),
    prompt_used: (g.prompt_used || '').slice(0, 4000),
    dialogue: g.dialogue || '', status: 'done'
  };
  const res = await this.helpers.httpRequest({
    method: 'POST', url: cfg.SUPABASE_URL + '/rest/v1/videos?on_conflict=output_id',
    headers: H, body: row, json: true });
  out.push({ json: { recorded_video: Array.isArray(res) ? res[0] : res } });
}
return out;

// Extracts the finished video URL and carries the metadata forward.
// No download happens here - the next node streams the file straight into
// n8n binary storage, so the MP4 never sits in this node's memory.
const ctx = $('C: Start Poll').all();
const items = $input.all();
const out = [];
for (let i = 0; i < items.length; i++) {
  const r = items[i].json || {};
  const carried = (ctx[i] ? ctx[i].json : ctx[0].json);
  const job = carried.job;
  if (carried._give_up === true) continue;   // video failed all attempts - skip, retried next run
  const v = r.video || r.output || {};
  const url = v.url || r.video_url || r.url || (r.videos && r.videos[0] && r.videos[0].url);
  if (!url) continue;   // no video url - skip, retried next run
  out.push({ json: {
    output_id: job.output_id, scenario_id: job.scenario_id,
    video_filename: 'video_o' + job.output_id + '__' + job.scenario_id + '.mp4',
    prompt_used: carried.video_prompt, dialogue: carried.dialogue,
    _url: url
  }, pairedItem: { item: i } });
}
return out;

// WORKER-MODE D planner. Builds the single TikTok post job for the video this
// Worker just made (Phase C wrote one row in `videos`). Honours TIKTOK_AUTO_POST.
const cfg = $('Config').first().json;
if (cfg.TIKTOK_AUTO_POST !== true) return [];   // feature off → no posts
const H = { apikey: cfg.SUPABASE_SECRET };

const wt = $('Worker Trigger').all();
const job = (wt && wt[0] && wt[0].json) || {};
if (!job.persona_id || !job.scenario) return [];

// ---- Look up the output Phase B wrote for this persona+scenario ----
const outputs = await this.helpers.httpRequest({ method: 'GET',
  url: cfg.SUPABASE_URL + '/rest/v1/outputs?select=id'
       + '&persona_id=eq.' + job.persona_id
       + '&scenario_id=eq.' + encodeURIComponent(job.scenario.id),
  headers: H, json: true });
if (!outputs || outputs.length === 0) return [];
const outputId = outputs[0].id;

// ---- Look up the video Phase C wrote for that output ----
const videos = await this.helpers.httpRequest({ method: 'GET',
  url: cfg.SUPABASE_URL + '/rest/v1/videos?select=id,drive_url,dialogue,output_id&output_id=eq.' + outputId,
  headers: H, json: true });
if (!videos || videos.length === 0) return [];
const v = videos[0];

// ---- Skip if this video already has a TikTok post (resumability) ----
let existing = [];
try {
  existing = await this.helpers.httpRequest({ method: 'GET',
    url: cfg.SUPABASE_URL + '/rest/v1/tiktok_posts?select=video_id&video_id=eq.' + v.id,
    headers: H, json: true });
} catch (e) { existing = []; }
if (existing && existing.length > 0) return [];

// ---- Look up persona → account → auth ----
const personas = await this.helpers.httpRequest({ method: 'GET',
  url: cfg.SUPABASE_URL + '/rest/v1/personas?select=id,tiktok_account_id&id=eq.' + job.persona_id,
  headers: H, json: true });
const persona = (personas && personas[0]) || {};
if (!persona.tiktok_account_id) return [];

const accounts = await this.helpers.httpRequest({ method: 'GET',
  url: cfg.SUPABASE_URL + '/rest/v1/tiktok_accounts?select=id,tiktok_id,name,country,language&id=eq.' + persona.tiktok_account_id,
  headers: H, json: true });
const account = (accounts && accounts[0]) || {};
if (!account.id) return [];

let auths = [];
try {
  auths = await this.helpers.httpRequest({ method: 'GET',
    url: cfg.SUPABASE_URL + '/rest/v1/tiktok_auth?select=*&tiktok_account_id=eq.' + account.id,
    headers: H, json: true });
} catch (e) { auths = []; }
const auth = (auths && auths[0]) || null;
if (!auth || !auth.access_token) return [];   // account not connected yet

return [{ json: {
  video_id: v.id, video_drive_url: v.drive_url, dialogue: v.dialogue || '',
  tiktok_account_id: account.id, tiktok_handle: account.tiktok_id,
  auth: { access_token: auth.access_token, refresh_token: auth.refresh_token,
          expires_at: auth.expires_at, open_id: auth.open_id }
} }];

// If the access_token is expired (or expires in < 60s), refresh it via
// TikTok OAuth and persist the new token. Otherwise passthrough.
const cfg = $('Config').first().json;
const H = { apikey: cfg.SUPABASE_SECRET, 'Content-Type': 'application/json', Prefer: 'return=representation' };
const now = Date.now();
const out = [];
for (const it of $input.all()) {
  const d = it.json;
  const exp = new Date(d.auth.expires_at).getTime();
  let auth = d.auth;
  if (exp - now < 60000) {
    // refresh
    const form = new URLSearchParams();
    form.append('client_key', cfg.TIKTOK_CLIENT_KEY);
    form.append('client_secret', cfg.TIKTOK_CLIENT_SECRET);
    form.append('grant_type', 'refresh_token');
    form.append('refresh_token', auth.refresh_token);
    const r = await this.helpers.httpRequest({
      method: 'POST', url: 'https://open.tiktokapis.com/v2/oauth/token/',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: form.toString(), json: true });
    if (r && r.access_token) {
      auth = { access_token: r.access_token,
               refresh_token: r.refresh_token || auth.refresh_token,
               expires_at: new Date(Date.now() + (r.expires_in || 86400) * 1000).toISOString(),
               open_id: auth.open_id };
      // persist new token
      await this.helpers.httpRequest({ method: 'PATCH',
        url: cfg.SUPABASE_URL + '/rest/v1/tiktok_auth?tiktok_account_id=eq.' + d.tiktok_account_id,
        headers: H, body: { access_token: auth.access_token, refresh_token: auth.refresh_token,
                            expires_at: auth.expires_at, updated_at: new Date().toISOString() },
        json: true });
    } else {
      // refresh failed - skip this job (will record failure later)
      out.push({ json: Object.assign({}, d, { _refresh_failed: true }) });
      continue;
    }
  }
  out.push({ json: Object.assign({}, d, { auth }) });
}
return out;

// Builds the TikTok /v2/post/publish/video/init/ request using PULL_FROM_URL.
// TikTok will fetch the video itself from the Drive URL - we send only metadata.
const cfg = $('Config').first().json;
return $input.all().map(it => {
  const d = it.json;
  if (d._refresh_failed) return { json: d };  // pass through so we can record the failure
  // caption: use dialogue as a starting caption, trimmed to TikTok's 2200-char limit
  const caption = String(d.dialogue || '').slice(0, 2000);
  return { json: Object.assign({}, d, {
    _url: 'https://open.tiktokapis.com/v2/post/publish/video/init/',
    _headers: {
      'Authorization': 'Bearer ' + d.auth.access_token,
      'Content-Type': 'application/json; charset=UTF-8'
    },
    _body: {
      post_info: {
        title: caption,
        privacy_level: cfg.TIKTOK_POST_PRIVACY || 'SELF_ONLY',
        disable_duet: false, disable_comment: false, disable_stitch: false,
        video_cover_timestamp_ms: 1000
      },
      source_info: {
        source: 'PULL_FROM_URL',
        video_url: d.video_drive_url
      }
    }
  }) };
});

// Reads the publish init response, prepares the status-poll context.
const prev = $('D: Build Init Request').all();
const items = $input.all();
const out = [];
for (let i = 0; i < items.length; i++) {
  const r = items[i].json || {};
  const carried = prev[i].json;
  if (carried._refresh_failed) {
    out.push({ json: Object.assign({}, carried, { _post_failed: true,
      _fail_reason: 'token refresh failed' }) });
    continue;
  }
  const publishId = (r && r.data && r.data.publish_id) || null;
  if (!publishId) {
    out.push({ json: Object.assign({}, carried, { _post_failed: true,
      _fail_reason: 'no publish_id (init error): ' + JSON.stringify(r).slice(0, 200) }) });
    continue;
  }
  out.push({ json: Object.assign({}, carried, {
    publish_id: publishId,
    _url: 'https://open.tiktokapis.com/v2/post/publish/status/fetch/',
    _headers: { 'Authorization': 'Bearer ' + carried.auth.access_token,
                'Content-Type': 'application/json; charset=UTF-8' },
    _body: { publish_id: publishId }
  }) });
}
return out;

// Inspect TikTok status response. Decide: done / keep polling / failed.
const ctx = $('D: Start Post Poll').all();
const items = $input.all();
let priorChecks = 0;
try { priorChecks = $('D: Check Post Status').all().length; } catch(e) { priorChecks = 0; }
if (priorChecks > 40) throw new Error('TikTok post status polling timed out.');
return items.map((it, i) => {
  const r = it.json || {};
  const carried = (ctx[i] ? ctx[i].json : ctx[0].json);
  if (carried._post_failed) return { json: Object.assign({}, carried, { _done: true }) };
  const status = (r && r.data && r.data.status) || '';
  if (status === 'PUBLISH_COMPLETE') {
    const url = (r.data.publicaly_available_post_id && Array.isArray(r.data.publicaly_available_post_id) && r.data.publicaly_available_post_id[0])
              || (r.data.public_post_id && Array.isArray(r.data.public_post_id) && r.data.public_post_id[0])
              || '';
    const postUrl = url ? ('https://www.tiktok.com/@' + (carried.tiktok_handle || '').replace(/^@/, '') + '/video/' + url) : '';
    return { json: Object.assign({}, carried, { _done: true, _post_failed: false, tiktok_post_url: postUrl }) };
  }
  if (status === 'FAILED') {
    const reason = (r.data && (r.data.fail_reason || r.data.error)) || 'TikTok reported FAILED';
    return { json: Object.assign({}, carried, { _done: true, _post_failed: true, _fail_reason: reason }) };
  }
  return { json: Object.assign({}, carried, { _done: false }) };
});

// Records the post outcome in tiktok_posts. UNIQUE(video_id) prevents dupes.
const cfg = $('Config').first().json;
const H = { apikey: cfg.SUPABASE_SECRET, 'Content-Type': 'application/json', Prefer: 'resolution=merge-duplicates,return=representation' };
for (const it of $input.all()) {
  const d = it.json;
  const body = {
    video_id: d.video_id,
    tiktok_account_id: d.tiktok_account_id,
    publish_id: d.publish_id || null,
    status: d._post_failed ? 'failed' : 'posted',
    tiktok_post_url: d.tiktok_post_url || null,
    error_reason: d._post_failed ? String(d._fail_reason || '').slice(0, 400) : null,
    posted_at: d._post_failed ? null : new Date().toISOString()
  };
  await this.helpers.httpRequest({ method: 'POST',
    url: cfg.SUPABASE_URL + '/rest/v1/tiktok_posts?on_conflict=video_id',
    headers: H, body, json: true });
}
return $input.all();
